#include <vector>
#include <algorithm>

long long solve(std::vector<long long> prices, std::vector<long long> strategy, long long k) {
    long long originalProfit = 0;
    int n = prices.size();
    for (int i = 0; i < n; ++i) {
        originalProfit += strategy[i] * prices[i];
    }

    std::vector<long long> prefixS(n + 1, 0);
    std::vector<long long> prefixP(n + 1, 0);

    for (int i = 0; i < n; ++i) {
        prefixS[i+1] = prefixS[i] + strategy[i] * prices[i];
        prefixP[i+1] = prefixP[i] + prices[i];
    }

    long long maxDelta = -1e18;
    int halfK = k / 2;

    for (int iStart = 0; iStart <= n - k; ++iStart) {
        int iEnd = iStart + k - 1;
        int startP = iStart + halfK;
        int endP = iEnd;
        long long sumP = prefixP[endP + 1] - prefixP[startP];
        long long sumS = prefixS[iEnd + 1] - prefixS[iStart];
        long long delta = sumP - sumS;
        if (delta > maxDelta) {
            maxDelta = delta;
        }
    }

    long long maxProfit = originalProfit + std::max(0LL, maxDelta);
    return maxProfit;
}
